#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

double randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

extern "C" __kernel void likelihood_kernel(
    double *arrayX,
    double *arrayY,
    double *xj,
    double *yj,
    double *CDF,
    int *ind,
    int *objxy,
    double *likelihood,
    unsigned char *I,
    double *u,
    double *weights,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr,
    int *seed,
    double *partial_sums,
    double local_sum)
{
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    arrayX[x] += 1.0 + 5.0 * randn(seed, x);
    arrayY[x] += -2.0 + 2.0 * randn(seed, x);

    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDouble(arrayX[x]) + objxy[y * 2 + 1];
        int indY = (int)roundDouble(arrayY[x]) + objxy[y * 2];
        int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (idx >= max_size) idx = 0;
        ind[x * countOnes + y] = idx;
    }

    double lik = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int val = I[ind[x * countOnes + y]];
        lik += ((pow((double)(val - 100), 2.0) - pow((double)(val - 228), 2.0)) / 50.0);
    }
    likelihood[x] = lik / (double)countOnes;

    weights[x] = weights[x] * exp(likelihood[x]);
}

extern "C" __kernel void sum_kernel(
    double *partial_sums,
    int Nparticles)
{
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    double sum = 0.0;
    for (int i = 0; i < Nparticles; i++) {
        sum += partial_sums[i];
    }
    partial_sums[Nparticles] = sum;
}

extern "C" __kernel void normalize_weights_kernel(
    double *weights,
    int Nparticles,
    double *partial_sums,
    double *CDF,
    double *u,
    int *seed)
{
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    double sumWeights = partial_sums[Nparticles];
    weights[x] = weights[x] / sumWeights;

    if (x == 0) {
        CDF[0] = weights[0];
    } else {
        CDF[x] = weights[x] + CDF[x - 1];
    }

    if (x == 0) {
        double u1 = (1.0 / (double)Nparticles) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + (double)i / (double)Nparticles;
        }
    }
}

extern "C" __kernel void find_index_kernel(
    double *arrayX,
    double *arrayY,
    double *CDF,
    double *u,
    double *xj,
    double *yj,
    double *weights,
    int Nparticles)
{
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    int i = findIndex(CDF, Nparticles, u[j]);
    if (i == -1) i = Nparticles - 1;

    xj[j] = arrayX[i];
    yj[j] = arrayY[i];

    arrayX[j] = xj[j];
    arrayY[j] = yj[j];
    weights[j] = 1.0 / (double)Nparticles;
}

